import { Skeleton } from ':components/Skeleton';

import { Typography } from ':components/Typography';
import React, { useEffect, useRef, useState } from 'react';

import { Country } from '../Countries.const';
import { Flag } from '../Flag';
import './CountrySelectItem.scss';

type CountrySelectItemProps = {
	value: Country;
	onClick: (event, value: Country) => void;
};

const CountrySelectItemComponent: React.FC<CountrySelectItemProps> = ({ value, onClick }) => {
	const [isFlagVisible, setIsFlagVisible] = useState(false);
	const itemRef = useRef<HTMLDivElement | null>(null);

	useEffect(() => {
		const node = itemRef.current;
		if (!node) {
			return;
		}

		// Если IntersectionObserver недоступен (старый браузер, тесты) — сразу показываем флаг.
		if (typeof IntersectionObserver === 'undefined') {
			setIsFlagVisible(true);
			return;
		}

		const observer = new IntersectionObserver(
			entries => {
				entries.forEach(entry => {
					if (entry.isIntersecting) {
						setIsFlagVisible(true);
						observer.disconnect();
					}
				});
			},
			{
				root: null,
				rootMargin: '80px 0px',
				threshold: 0.1,
			},
		);

		observer.observe(node);

		return () => {
			observer.disconnect();
		};
	}, []);

	return (
		<div ref={itemRef} className="dsb_phoneinput__dropdown__item" onClick={event => onClick(event, value)}>
			<div className="dsb_phoneinput__dropdown__item-flag">
				{isFlagVisible ? <Flag value={value} /> : <Skeleton width={20} height={20} />}
			</div>
			<Typography variant="body2" className="dsb_phoneinput__dropdown__item__name">
				{value.name} ({value.nameCode})
			</Typography>
			<Typography variant="body2" inactive>
				{value.phoneCode}
			</Typography>
		</div>
	);
};

export const CountrySelectItem = React.memo(
	CountrySelectItemComponent,
	(prev, next) => prev.value.nameCode === next.value.nameCode && prev.onClick === next.onClick,
);
